solution_code:
#include <iostream>

template <typename T, typename U>
auto scale(T a, U b)
{
    return a * b;
}

int main()
{
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i)
    {
        int    a;
        double b;
        std::cin >> a >> b;
        std::cout << "scale: " << scale(a, b) << '\n';
    }
    return 0;
}

